def mystery(x):
    import hashlib
    import hmac

    if type(x) is not str:
        return False
    if not x.isascii():
        return False

    try:
        a, b = x.split("|")
    except ValueError:
        return False

    if len(a) != 56 or len(b) != 28:
        return False

    left = hashlib.sha256(a[::-1].encode("ascii")).hexdigest()
    right = hmac.new(b"Jefe", b[::-1].encode("ascii"), hashlib.sha256).hexdigest()

    return (
        hmac.compare_digest(
            left,
            "248d6a61d20638b8e5c026930c3e6039a33ce45964ff2167f6ecedd419db06c1",
        )
        and hmac.compare_digest(
            right,
            "5bdcc146bf60754e6a042426089575c75a003f089d2739839dec58b964ec3843",
        )
    )
